use std::sync::{Arc, Mutex};
use std::collections::VecDeque;
use std::thread;

fn main() {
    let queue = Arc::new(Mutex::new(VecDeque::<i32>::new()));
    let mut handles = vec![];
    for i in 0..3i32 {
        let q = Arc::clone(&queue);
        handles.push(thread::spawn(move || {
            q.lock().unwrap().push_back(i * 10);
        }));
    }
    for h in handles.drain(..) { h.join().unwrap(); }
    let mut items: Vec<i32> = queue.lock().unwrap().drain(..).collect();
    items.sort(); // deterministic output
    for v in items { println!("consumed: {}", v); }
